// ============================================
// KONFIGURACJA ZESPOŁÓW
// Podmień LIST_ID na prawdziwe ID z ClickUp
// ============================================

const TEAMS_CONFIG = {
  'hostessy': {
    listId: 'LIST_ID_HOSTESSY',
    managerEmail: 'manager.hostessy@agencja.pl',
    managerName: 'Manager Hostess',
    typProduktu: 'Coca-Cola',
    jednostka: 'puszki',
    godzinaStart: '08:00',
    godzinaKoniec: '18:00',
    godzinaRaportPolowkowy: '13:00',
    maxSpoznienieAlertMin: 15,
    maxSpoznienAlertZarzad: 3
  },
  'rejestracja': {
    listId: 'LIST_ID_REJESTRACJA',
    managerEmail: 'manager.rejestracja@agencja.pl',
    managerName: 'Manager Rejestracji',
    typProduktu: 'Identyfikatory',
    jednostka: 'szt',
    godzinaStart: '07:30',
    godzinaKoniec: '17:00',
    godzinaRaportPolowkowy: '12:30',
    maxSpoznienieAlertMin: 10,
    maxSpoznienAlertZarzad: 2
  },
  'logistyka': {
    listId: 'LIST_ID_LOGISTYKA',
    managerEmail: 'manager.logistyka@agencja.pl',
    managerName: 'Manager Logistyki',
    typProduktu: 'Paczki',
    jednostka: 'szt',
    godzinaStart: '07:00',
    godzinaKoniec: '19:00',
    godzinaRaportPolowkowy: '13:00',
    maxSpoznienieAlertMin: 15,
    maxSpoznienAlertZarzad: 3
  },
  'ochrona': {
    listId: 'LIST_ID_OCHRONA',
    managerEmail: 'manager.ochrona@agencja.pl',
    managerName: 'Manager Ochrony',
    typProduktu: 'Przepustki',
    jednostka: 'szt',
    godzinaStart: '06:00',
    godzinaKoniec: '22:00',
    godzinaRaportPolowkowy: '14:00',
    maxSpoznienieAlertMin: 5,
    maxSpoznienAlertZarzad: 2
  },
  'catering': {
    listId: 'LIST_ID_CATERING',
    managerEmail: 'manager.catering@agencja.pl',
    managerName: 'Manager Cateringu',
    typProduktu: 'Posilki',
    jednostka: 'porcje',
    godzinaStart: '09:00',
    godzinaKoniec: '20:00',
    godzinaRaportPolowkowy: '14:00',
    maxSpoznienieAlertMin: 10,
    maxSpoznienAlertZarzad: 3
  },
  'vip': {
    listId: 'LIST_ID_VIP',
    managerEmail: 'manager.vip@agencja.pl',
    managerName: 'Manager VIP',
    typProduktu: 'VIP Pakiety',
    jednostka: 'szt',
    godzinaStart: '08:00',
    godzinaKoniec: '18:00',
    godzinaRaportPolowkowy: '13:00',
    maxSpoznienieAlertMin: 10,
    maxSpoznienAlertZarzad: 2
  }
};

// Stałe
const ZARZAD_EMAIL = 'zarzad@agencja.pl';
const ZARZAD_EMAIL_2 = 'dyrektor@agencja.pl';
const SYSTEM_EMAIL = 'system@agencja.pl';

// Pobierz dane z webhooka
const raw = $input.first().json;
const data = raw.body || raw;

// Normalizuj nazwę zespołu
const zespolKey = (data.zespol || '').toLowerCase()
  .trim()
  .replace(/ó/g, 'o')
  .replace(/ą/g, 'a')
  .replace(/ę/g, 'e')
  .replace(/ś/g, 's')
  .replace(/ź|ż/g, 'z')
  .replace(/ć/g, 'c')
  .replace(/ń/g, 'n')
  .replace(/ł/g, 'l');

const teamConfig = TEAMS_CONFIG[zespolKey] || null;

// Walidacja
const errors = [];
if (!data.imie_nazwisko || data.imie_nazwisko.trim() === '') {
  errors.push('Brak imienia i nazwiska');
}
if (!data.email || !data.email.includes('@')) {
  errors.push('Nieprawidlowy email');
}
if (!data.zespol) {
  errors.push('Brak nazwy zespolu');
}
if (!teamConfig) {
  errors.push('Nieznany zespol: ' + data.zespol + '. Dostepne: ' + Object.keys(TEAMS_CONFIG).join(', '));
}
if (!data.stan_poczatkowy || isNaN(parseInt(data.stan_poczatkowy))) {
  errors.push('Brak lub nieprawidlowy stan poczatkowy towaru');
}

if (errors.length > 0) {
  return [{ json: { isValid: false, errors, data } }];
}

// Oblicz czas i spóźnienie
const now = new Date();
const godzinaPrzyjscia = data.godzina_przyjscia ||
  now.getHours().toString().padStart(2, '0') + ':' +
  now.getMinutes().toString().padStart(2, '0');

const [hP, mP] = godzinaPrzyjscia.split(':').map(Number);
const [hS, mS] = teamConfig.godzinaStart.split(':').map(Number);
const minutyPrzyjscia = hP * 60 + mP;
const minutyStart = hS * 60 + mS;
const spoznienieMiny = minutyPrzyjscia - minutyStart;

const czyPunktualna = spoznienieMiny <= 0;
const czySpozniona = spoznienieMiny > teamConfig.maxSpoznienieAlertMin;

const dataFormatted = now.toLocaleDateString('pl-PL', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

const dataNazwa = now.toLocaleDateString('pl-PL', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

return [{
  json: {
    // Dane pracownika
    imie_nazwisko: data.imie_nazwisko.trim(),
    email: data.email.trim().toLowerCase(),
    telefon: data.telefon || '',
    zespol: data.zespol,
    zespolKey,
    stanPoczatkowy: parseInt(data.stan_poczatkowy),
    uwagi: data.uwagi || '',

    // Konfiguracja
    teamConfig,
    listId: teamConfig.listId,
    managerEmail: teamConfig.managerEmail,
    managerName: teamConfig.managerName,
    zarzadEmail: ZARZAD_EMAIL,
    zarzadEmail2: ZARZAD_EMAIL_2,
    systemEmail: SYSTEM_EMAIL,

    // Czas
    godzinaPrzyjscia,
    spoznienieMiny,
    czyPunktualna,
    czySpozniona,
    dataFormatted,
    dataNazwa,
    timestamp: now.toISOString(),

    // Status
    etapStartowy: '2 - Zameldowana',
    statusObecnosci: czySpozniona ? 'Obecny - spoźniony' : 'Obecny - punktualny',
    postep: 25,

    isValid: true,
    errors: []
  }
}];

