const now = new Date();

const warsawTime = new Date(
  now.toLocaleString('en-US', { timeZone: 'Europe/Warsaw' })
);

const currentHour = warsawTime.getHours();
const currentMin = warsawTime.getMinutes();
const currentTotalMin = currentHour * 60 + currentMin;

return [{
  json: {
    nowUTC: now.toISOString(),
    nowWarsaw: warsawTime.toString(),
    currentHour,
    currentMin,
    currentTotalMin
  }
}];

const teamCfg = $('SETUP - Konfiguracja Zespołów').item.json;
const tasks = $input.first().json.tasks || [];

// ✅ CZAS – zawsze Polska
const now = new Date();
const localNow = new Date(
  now.toLocaleString('en-US', { timeZone: 'Europe/Warsaw' })
);

// ✅ funkcja do bezpiecznego parsowania czasu
function parseTime(str) {
  if (!str || typeof str !== 'string') return null;

  const parts = str.split(':');
  if (parts.length < 2) return null;

  const h = parseInt(parts[0]);
  const m = parseInt(parts[1]);

  if (isNaN(h) || isNaN(m)) return null;

  return h * 60 + m;
}

// ✅ start dnia
const startTotalMin = parseTime(teamCfg.godzinaStart);

// aktualny czas
const nowTotalMin = localNow.getHours() * 60 + localNow.getMinutes();
const minPoStartcie = nowTotalMin - startTotalMin;

// ❌ jeszcze za wcześnie
if (minPoStartcie < 0) {
  return [{
    json: {
      skip: true,
      reason: 'Za wczesnie',
      team: teamCfg.name,
      nowLocal: localNow.toString()
    }
  }];
}

// =====================
// 📊 STATYSTYKI
// =====================
const problemy = [];

const statystyki = {
  team: teamCfg.name,
  lacznie: tasks.length,
  obecni: 0,
  spoznieni: 0,
  nieobecni: 0,
  bezRaportuPolowkowego: 0,
  bezRaportuKoncowego: 0,
  wymagaUwagi: 0
};

// =====================
// 🔍 ANALIZA TASKÓW
// =====================
tasks.forEach(task => {

  // mapowanie custom fields
  const cf = {};
  (task.custom_fields || []).forEach(f => {
    cf[f.name] = f.value;
  });

  const godzinaPrzyjscia = cf['Godzina Przyjscia'];
  const statusObecnosci = cf['Status Obecnosci'];
  const liczbaSpozn = parseInt(cf['Liczba Spoźnień'] || '0');
  const raportPol = cf['Raport Polowkowy'];
  const raportKon = cf['Raport Koncowy'];
  const emailPrac = cf['Email Pracownika'];

  const przyjTotal = parseTime(godzinaPrzyjscia);

  // =====================
  // ✅ OBECNOŚĆ
  // =====================
  if (przyjTotal !== null) {
    statystyki.obecni++;

    const spoznMin = przyjTotal - startTotalMin;

    if (spoznMin > teamCfg.maxSpoznMin) {
      statystyki.spoznieni++;

      problemy.push({
        typ: 'spoznienie',
        taskId: task.id,
        taskUrl: task.url,
        imie: task.name.split(' | ')[0],
        email: emailPrac,
        spoznMin,
        liczbaSpozn,
        alertZarzad: liczbaSpozn >= teamCfg.alertZarzadPo,
        wiadomosc: `Spóźnienie ${spoznMin} min (${liczbaSpozn + 1}x)`
      });
    }

  // =====================
  // ❌ NIEOBECNOŚĆ
  // =====================
  } else if (!godzinaPrzyjscia && minPoStartcie > 30) {

    statystyki.nieobecni++;

    problemy.push({
      typ: 'nieobecnosc',
      taskId: task.id,
      taskUrl: task.url,
      imie: task.name.split(' | ')[0],
      email: emailPrac,
      minutyPo: minPoStartcie,
      alertZarzad: minPoStartcie > 60,
      wiadomosc: `Nieobecna ${minPoStartcie} min po starcie`
    });
  }

  // =====================
  // 📋 RAPORT POŁÓWKOWY
  // =====================
  const godzinaRapPol = teamCfg.godzinaRaportPolowkowy || '13:00';
  const rapTotalMin = parseTime(godzinaRapPol);

  if (
    rapTotalMin &&
    nowTotalMin > rapTotalMin + 30 &&
    !raportPol &&
    przyjTotal !== null
  ) {
    statystyki.bezRaportuPolowkowego++;

    problemy.push({
      typ: 'brak_raportu_polowkowego',
      taskId: task.id,
      taskUrl: task.url,
      imie: task.name.split(' | ')[0],
      email: emailPrac,
      alertZarzad: false,
      wiadomosc: 'Brak raportu połówkowego'
    });
  }

  // =====================
  // ⚠️ STATUS
  // =====================
  if (task.status && task.status.status === 'Wymaga uwagi') {
    statystyki.wymagaUwagi++;
  }
});

// =====================
// 📦 OUTPUT
// =====================
return [{
  json: {
    ...teamCfg,
    skip: false,
    statystyki,
    problemy,
    maProblemy: problemy.length > 0,
    alertZarzadWymagany: problemy.some(p => p.alertZarzad),

    // debug (polecam zostawić!)
    nowUTC: now.toISOString(),
    nowLocal: localNow.toString(),
    nowTotalMin,
    startTotalMin,
    minPoStartcie
  }
}];

const data = $input.first().json;
const problemy = data.problemy || [];

// Buduj HTML emaila dla managera
const listaProbl = problemy.map(p => {
  const kolor = p.typ === 'spoznienie' ? '#fff3cd' :
                p.typ === 'nieobecnosc' ? '#f8d7da' : '#d1ecf1';
  const ikona = p.typ === 'spoznienie' ? '⚠️' :
                p.typ === 'nieobecnosc' ? '❌' : '📋';
  return `<div style='background:${kolor};border-radius:6px;padding:12px;margin:8px 0;'>
    <strong>${ikona} ${p.imie}</strong> - ${p.wiadomosc}
    ${p.alertZarzad ? '<span style="color:red;font-weight:bold;"> 🚨 ALERT ZARZĄD</span>' : ''}
    <br><a href='${p.taskUrl}' style='font-size:12px;color:#666;'>Zobacz task →</a>
  </div>`;
}).join('');

const emailHTML = `<!DOCTYPE html><html><body style='font-family:Arial;max-width:600px;margin:0 auto;'>
<div style='background:#e74c3c;color:white;padding:20px;border-radius:10px 10px 0 0;'>
  <h2 style='margin:0;'>🔔 Alert - Zespół: ${data.name}</h2>
  <p style='opacity:0.9;margin:5px 0 0;'>${new Date().toLocaleString('pl-PL')}</p>
</div>
<div style='background:white;padding:20px;border:1px solid #eee;'>
  <h3>📊 Statystyki Zespołu</h3>
  <table style='width:100%;border-collapse:collapse;'>
    <tr><td style='padding:6px;border-bottom:1px solid #eee;'>Łącznie:</td><td style='padding:6px;border-bottom:1px solid #eee;font-weight:bold;'>${data.statystyki.lacznie}</td></tr>
    <tr><td style='padding:6px;border-bottom:1px solid #eee;'>Obecni:</td><td style='padding:6px;border-bottom:1px solid #eee;color:green;font-weight:bold;'>${data.statystyki.obecni}</td></tr>
    <tr><td style='padding:6px;border-bottom:1px solid #eee;'>Spóźnieni:</td><td style='padding:6px;border-bottom:1px solid #eee;color:orange;font-weight:bold;'>${data.statystyki.spoznieni}</td></tr>
    <tr><td style='padding:6px;'>Nieobecni:</td><td style='padding:6px;color:red;font-weight:bold;'>${data.statystyki.nieobecni}</td></tr>
  </table>
  <h3>⚠️ Problemy (${problemy.length})</h3>
  ${listaProbl}
</div>
<div style='background:#f8f9fa;padding:12px;text-align:center;border-radius:0 0 10px 10px;border:1px solid #eee;'>
  <p style='color:#888;font-size:11px;margin:0;'>Automatyczny alert | ${new Date().toLocaleString('pl-PL')}</p>
</div></body></html>`;

return [{
  json: {
    ...data,
    emailHTML,
    emailSubject: `🔔 [${data.name}] ${problemy.length} problemów | ${new Date().toLocaleTimeString('pl-PL')}`
  }
}];

const TEAMS = [
  { name: 'Hostessy', listId: 'LIST_ID_HOSTESSY', managerEmail: 'manager.hostessy@agencja.pl', typProduktu: 'Coca-Cola', jednostka: 'puszki' },
  { name: 'Rejestracja', listId: 'LIST_ID_REJESTRACJA', managerEmail: 'manager.rejestracja@agencja.pl', typProduktu: 'Identyfikatory', jednostka: 'szt' },
  { name: 'Logistyka', listId: 'LIST_ID_LOGISTYKA', managerEmail: 'manager.logistyka@agencja.pl', typProduktu: 'Paczki', jednostka: 'szt' },
  { name: 'Ochrona', listId: 'LIST_ID_OCHRONA', managerEmail: 'manager.ochrona@agencja.pl', typProduktu: 'Przepustki', jednostka: 'szt' },
  { name: 'Catering', listId: 'LIST_ID_CATERING', managerEmail: 'manager.catering@agencja.pl', typProduktu: 'Posilki', jednostka: 'porcje' },
  { name: 'VIP', listId: 'LIST_ID_VIP', managerEmail: 'manager.vip@agencja.pl', typProduktu: 'VIP Pakiety', jednostka: 'szt' }
];

const now = new Date();
const dateStr = now.toLocaleDateString('pl-PL');

return TEAMS.map(team => ({ json: { ...team, dateStr, timestamp: now.toISOString(), systemEmail: 'system@agencja.pl', zarzadEmail: 'zarzad@agencja.pl' } }));

const teamCfg = $('SETUP - Lista Wszystkich Zespołów').item.json;
const tasks = $input.first().json.tasks || [];

const pracownicy = tasks.map(task => {
  const cf = {};
  (task.custom_fields || []).forEach(f => { cf[f.name] = f.value; });

  const stanPocz = parseInt(cf['Stan Poczatkowy'] || '0');
  const stanPol = parseInt(cf['Stan Polowkowy'] || '0');
  const stanKon = parseInt(cf['Stan Koncowy'] || '0');
  const rozdano = stanKon > 0 ? stanPocz - stanKon : (stanPol > 0 ? stanPocz - stanPol : 0);

  return {
    id: task.id,
    url: task.url,
    imie: task.name.split(' | ')[0],
    status: task.status ? task.status.status : 'nieznany',
    godzinaPrzyjscia: cf['Godzina Przyjscia'] || '—',
    godzinaWyjscia: cf['Godzina Wyjscia'] || '—',
    czyZarej: cf['Czy Zarejestrowana'] === 'true',
    stanPocz,
    stanPol,
    stanKon,
    rozdano,
    etap: cf['Aktualny Etap'] || '—',
    raportPol: cf['Raport Polowkowy'] || '',
    raportKon: cf['Raport Koncowy'] || '',
    uwagi: cf['Uwagi Managera'] || '',
    email: cf['Email Pracownika'] || ''
  };
});

const stats = {
  lacznie: pracownicy.length,
  obecni: pracownicy.filter(p => p.godzinaPrzyjscia !== '—').length,
  nieobecni: pracownicy.filter(p => p.godzinaPrzyjscia === '—').length,
  zakonczone: pracownicy.filter(p => p.status === 'Zakończona').length,
  zRaportPol: pracownicy.filter(p => p.raportPol).length,
  zRaportKon: pracownicy.filter(p => p.raportKon).length,
  lacznie_rozdano: pracownicy.reduce((s, p) => s + p.rozdano, 0),
  srednia_rozdano: pracownicy.length > 0
    ? Math.round(pracownicy.reduce((s, p) => s + p.rozdano, 0) / pracownicy.filter(p => p.godzinaPrzyjscia !== '—').length || 0)
    : 0
};

const problemy = {
  bezRaportKon: pracownicy.filter(p => !p.raportKon && p.godzinaPrzyjscia !== '—'),
  nieobecni: pracownicy.filter(p => p.godzinaPrzyjscia === '—'),
  niezakonczone: pracownicy.filter(p => p.status !== 'Zakończona' && p.godzinaPrzyjscia !== '—')
};

return [{
  json: {
    ...teamCfg,
    pracownicy,
    stats,
    problemy,
    maProblemy: problemy.bezRaportKon.length > 0 || problemy.nieobecni.length > 0
  }
}];

const data = $input.first().json;
const { pracownicy, stats, problemy } = data;

// Tabela pracowników
const wiersze = pracownicy.map((p, i) => {
  const bg = i % 2 === 0 ? '#f8f9fa' : 'white';
  const statusKolor = p.status === 'Zakończona' ? 'green' : p.status === 'Wymaga uwagi' ? 'red' : 'orange';
  return `<tr style='background:${bg};'>
    <td style='padding:8px;border:1px solid #dee2e6;'>${p.imie}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.godzinaPrzyjscia}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.godzinaWyjscia}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.czyZarej ? '✅' : '❌'}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.stanPocz}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.stanPol || '—'}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;font-weight:bold;'>${p.rozdano}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.stanKon || '—'}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.raportPol ? '✅' : '❌'}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;'>${p.raportKon ? '✅' : '❌'}</td>
    <td style='padding:8px;border:1px solid #dee2e6;text-align:center;color:${statusKolor};font-weight:bold;'>${p.status}</td>
  </tr>`;
}).join('');

// Sekcja problemów
let sekcjaProbl = '';
if (data.maProblemy) {
  sekcjaProbl = `<div style='background:#fff3cd;border:1px solid #ffc107;border-radius:8px;padding:15px;margin:15px 0;'>
    <h3 style='color:#856404;margin-top:0;'>⚠️ Problemy do Wyjaśnienia</h3>
    ${problemy.bezRaportKon.length > 0 ? `<p><strong>Brak raportu końcowego:</strong> ${problemy.bezRaportKon.map(p => p.imie).join(', ')}</p>` : ''}
    ${problemy.nieobecni.length > 0 ? `<p><strong>Nieobecni bez zgłoszenia:</strong> ${problemy.nieobecni.map(p => p.imie).join(', ')}</p>` : ''}
    ${problemy.niezakonczone.length > 0 ? `<p><strong>Nie zamknęli dyżuru:</strong> ${problemy.niezakonczone.map(p => p.imie).join(', ')}</p>` : ''}
  </div>`;
}

// Raporty indywidualne
const raportyHTML = pracownicy
  .filter(p => p.raportKon || p.raportPol)
  .map(p => `<div style='background:#f8f9fa;border-radius:6px;padding:12px;margin:8px 0;border-left:3px solid #667eea;'>
    <strong>${p.imie}</strong>
