const lists = items.map(i => i.json);

// 📅 dzisiejsza data (Polska)
const now = new Date();
const localNow = new Date(
  now.toLocaleString('en-US', { timeZone: 'Europe/Warsaw' })
);

// format DD-MM
const day = String(localNow.getDate()).padStart(2, '0');
const month = String(localNow.getMonth() + 1).padStart(2, '0');
const todayStr = `${day}-${month}`;

// 🔍 znajdź listę, której nazwa zawiera dzisiejszą datę
let todayList = lists.find(l => l.name && l.name.includes(todayStr));

// 🔁 fallback — jeśli nie znajdzie dokładnej daty
if (!todayList) {
  console.log('⚠️ Nie znaleziono listy z dzisiejszą datą, wybieram ostatnią aktywną');

  todayList = lists
    .filter(l => l.task_count > 0)
    .sort((a, b) => b.task_count - a.task_count)[0];
}

// ❌ nadal nic nie znaleziono
if (!todayList) {
  throw new Error('❌ Nie znaleziono żadnej listy dzisiejszej ani aktywnej');
}

// 📦 OUTPUT
return [{
  json: {
    listId: todayList.id,
    listName: todayList.name,
    todayStr,
    znalezionoExact: todayList.name.includes(todayStr)
  }
}];
